// CSD_RATIONALE_BEGIN
// Given the strict arithmetic expression grammar and the requirement that every expression must contain at least one variable,
// I chose a multi-step approach that combines speculative generation with repair/complete to balance creativity with validity.
// The speculative generation allows for early exploration of creative solutions, while the repair/complete step ensures that the final
// expression is valid and meets the constraints.
// CSD_RATIONALE_END

var intermediateGenerated: Prefix;
var intermediateCost: int;

// Attempt speculative generation first
generated := helpers.SpeculativeGeneration(lm, parser, prompt, maxSteps, 4);
cost := helpers.cost;

// Check if the generated expression contains at least one variable
if helpers.ExtractContentBetweenDelimiters(helpers.PrefixToString(generated), "<<", ">>").ContainsAnyVar() {
  return; // Valid expression generated
} else {
  // If no variable is found, revert to pure constrained generation
  intermediateGenerated := helpers.PureConstrainedGeneration(lm, parser, prompt, maxSteps);
  intermediateCost := helpers.cost;

  // Combine the initial partial result with the full constrained result
  generated := intermediateGenerated + helpers.CompletePrefix(lm, parser, intermediateGenerated, intermediateGenerated, maxSteps);
  cost := intermediateCost + helpers.cost;
}

// Ensure the final generated expression contains at least one variable
if !helpers.ExtractContentBetweenDelimiters(helpers.PrefixToString(generated), "<<", ">>").ContainsAnyVar() {
  generated := helpers.PureConstrainedGeneration(lm, parser, prompt, maxSteps);
  cost := helpers.cost;
}

// Ensure the generated expression is complete and valid
assert parser.IsValidPrefix(generated);
assert parser.IsCompletePrefix(generated);

// Ensure the cost does not exceed twice the maximum steps
assert cost <= 2 * maxSteps;

